svg.script:

// State Configuration
let currentForce = 'lift';

// Physics variables
let forces = {
    'lift': 5000,
    'weight': 5000,
    'thrust': 2000,
    'drag': 2000
};

// Animation states
let lastTime = 0;
let altitude = 0; // Ground is 0
let verticalVelocity = 0;
let horizontalVelocity = 0;
let cloudX = 0;
let aircraftXOffset = 0; // Visual forward/backward movement

// Slider Configurations
const SLIDER_WIDTH = 350;
let activeSlider = null;

const sliderConfig = {
    'lift': { min: 0, max: 10000, baseLine: 100 },
    'weight': { min: 0, max: 10000, baseLine: 100 },
    'thrust': { min: 0, max: 5000, baseLine: 100 },
    'drag': { min: 0, max: 5000, baseLine: 100 }
};

// UI Text Data
const forceData = {
    'lift': {
        color: '#10b981',
        title: 'LIFT',
        desc: 'The upward force created by the main rotor blades spinning through the air. Lift directly opposes weight. When lift is greater than weight, the helicopter accelerates upward (climbs). When they are perfectly equal, it hovers or maintains level flight.'
    },
    'weight': {
        color: '#ef4444',
        title: 'WEIGHT (GRAVITY)',
        desc: 'The downward force of gravity pulling on the mass of the helicopter, fuel, and payload. To fly, the main rotor must generate enough lift to overcome this constant downward force.'
    },
    'thrust': {
        color: '#3b82f6',
        title: 'THRUST',
        desc: 'The forward force produced by tilting the main rotor disc forward. Thrust overcomes drag to push the helicopter forward through the air. If Thrust is greater than Drag, the helicopter accelerates forward.'
    },
    'drag': {
        color: '#f97316',
        title: 'DRAG (OR REVERSE THRUST)',
        desc: 'The backward aerodynamic resistance the helicopter experiences, or the reverse thrust generated by tilting the rotor backward. If Drag/Reverse exceeds forward Thrust, the helicopter will fly backward!'
    }
};

function initSimulation() {
    setForce('lift');
    updateVectors();
    requestAnimationFrame(animationLoop);
}

// Tab Selection
function setForce(forceId) {
    currentForce = forceId;
    const data = forceData[forceId];

    // Update Tabs
    document.querySelectorAll('.tab').forEach(el => el.classList.remove('active'));
    document.getElementById('tab-' + forceId).classList.add('active');

    // Reset Glows
    document.querySelectorAll('.force-arrow-glow').forEach(el => el.style.opacity = '0');
    document.getElementById('glow-' + forceId).style.opacity = '1';

    // Update Info Panel
    document.getElementById('info-badge').style.backgroundColor = data.color;
    document.getElementById('info-title').textContent = data.title;
    document.getElementById('info-desc').innerHTML = data.desc;
}

// Drag Handling
function getClientX(evt) {
    if (evt.touches && evt.touches.length > 0) return evt.touches[0].clientX;
    if (evt.changedTouches && evt.changedTouches.length > 0) return evt.changedTouches[0].clientX;
    return evt.clientX;
}
function getClientY(evt) {
    if (evt.touches && evt.touches.length > 0) return evt.touches[0].clientY;
    if (evt.changedTouches && evt.changedTouches.length > 0) return evt.changedTouches[0].clientY;
    return evt.clientY;
}

function startDrag(evt, id) {
    activeSlider = id;
    setForce(id);
    updateDrag(evt);
}
function startDragTouch(evt, id) {
    evt.preventDefault();
    activeSlider = id;
    setForce(id);
    updateDrag(evt);
}

function onMouseMove(evt) {
    if (activeSlider) updateDrag(evt);
}
function onMouseUp(evt) {
    activeSlider = null;
}
function onTouchMove(evt) {
    if (activeSlider) { evt.preventDefault(); updateDrag(evt); }
}
function onTouchEnd(evt) {
    activeSlider = null;
}

function updateDrag(evt) {
    const svg = document.getElementById('main-svg');
    const pt = svg.createSVGPoint();
    pt.x = getClientX(evt);
    pt.y = getClientY(evt);
    const svgP = pt.matrixTransform(svg.getScreenCTM().inverse());

    // Sliders track starts at x=770
    let localX = svgP.x - 770;
    if (localX < 0) localX = 0;
    if (localX > SLIDER_WIDTH) localX = SLIDER_WIDTH;

    const conf = sliderConfig[activeSlider];
    forces[activeSlider] = conf.min + (localX / SLIDER_WIDTH) * (conf.max - conf.min);

    // Update Slider Visuals
    document.getElementById('track-' + activeSlider).setAttribute('x2', localX);
    document.getElementById('thumb-' + activeSlider).setAttribute('cx', localX);
    document.getElementById('slider-val-' + activeSlider).textContent = Math.round(forces[activeSlider]) + ' lbs';

    updateVectors();
}

function updateVectors() {
    // Map forces to pixel lengths for the arrows
    const liftLen = Math.max(20, (forces.lift / 10000) * 150);
    const weightLen = Math.max(20, (forces.weight / 10000) * 150);
    const thrustLen = Math.max(20, (forces.thrust / 5000) * 150);
    const dragLen = Math.max(20, (forces.drag / 5000) * 150);

    // Update SVG lines
    document.getElementById('arr-lift').setAttribute('y2', -liftLen);
    document.getElementById('glow-lift').setAttribute('y2', -liftLen);
    document.getElementById('lbl-lift-title').setAttribute('y', -liftLen - 15);
    document.getElementById('lbl-lift-val').setAttribute('y', -liftLen - 30);
    document.getElementById('lbl-lift-val').textContent = Math.round(forces.lift) + ' lbs';

    document.getElementById('arr-weight').setAttribute('y2', weightLen);
    document.getElementById('glow-weight').setAttribute('y2', weightLen);
    document.getElementById('lbl-weight-title').setAttribute('y', weightLen + 25);
    document.getElementById('lbl-weight-val').setAttribute('y', weightLen + 40);
    document.getElementById('lbl-weight-val').textContent = Math.round(forces.weight) + ' lbs';

    document.getElementById('arr-thrust').setAttribute('x2', thrustLen);
    document.getElementById('glow-thrust').setAttribute('x2', thrustLen);
    document.getElementById('lbl-thrust-title').setAttribute('x', thrustLen + 15);
    document.getElementById('lbl-thrust-val').setAttribute('x', thrustLen + 15);
    document.getElementById('lbl-thrust-val').textContent = Math.round(forces.thrust) + ' lbs';

    document.getElementById('arr-drag').setAttribute('x2', -dragLen);
    document.getElementById('glow-drag').setAttribute('x2', -dragLen);
    document.getElementById('lbl-drag-title').setAttribute('x', -dragLen - 15);
    document.getElementById('lbl-drag-val').setAttribute('x', -dragLen - 15);
    document.getElementById('lbl-drag-val').textContent = Math.round(forces.drag) + ' lbs';

    // Update Equations Box
    const netY = forces.lift - forces.weight;
    const netX = forces.thrust - forces.drag;

    document.getElementById('eq-vertical').textContent = `Vertical: ${Math.round(forces.lift)} - ${Math.round(forces.weight)} = ${Math.round(netY)} lbs`;
    document.getElementById('eq-horizontal').textContent = `Horizontal: ${Math.round(forces.thrust)} - ${Math.round(forces.drag)} = ${Math.round(netX)} lbs`;
}

// 60fps Physics & Animation Loop
function animationLoop(timestamp) {
    if (!lastTime) lastTime = timestamp;
    const dt = timestamp - lastTime || 16;
    lastTime = timestamp;

    // Physics calculations
    const netY = forces.lift - forces.weight;
    const netX = forces.thrust - forces.drag;

    // Apply acceleration to velocity (scaled for visual effect)
    verticalVelocity += netY * 0.0002 * (dt / 16);
    horizontalVelocity += netX * 0.0002 * (dt / 16);

    // Apply natural air drag/friction to velocities
    verticalVelocity *= 0.98; 
    horizontalVelocity *= 0.98; 

    // Cap absolute max horizontal speed
    if (horizontalVelocity > 60) horizontalVelocity = 60;
    if (horizontalVelocity < -60) horizontalVelocity = -60;

    // Update positions
    altitude += verticalVelocity * (dt / 16);

    // Ground collision
    if (altitude <= 0) {
        altitude = 0;
        if (verticalVelocity < 0) verticalVelocity = 0;

        // High ground friction stops horizontal movement quickly
        if (Math.abs(netX) < 100) {
            horizontalVelocity *= 0.85; 
        }
    }

    // Ceiling limit (visual constraint so it stays in the box)
    if (altitude > 200) {
        altitude = 200;
    }

    // Animate Background (Clouds moving opposite to velocity)
    cloudX -= horizontalVelocity * (dt / 16);
    if (cloudX <= -1200) cloudX += 1200; // Loop clouds left
    if (cloudX >= 1200) cloudX -= 1200;  // Loop clouds right
    document.getElementById('clouds').setAttribute('transform', `translate(${cloudX}, 0)`);

    // Parallax Ground
    if (altitude < 200) {
        document.getElementById('ground-layer').style.display = 'block';
        const groundY = 230 + altitude * 1.5; 
        document.getElementById('ground-layer').setAttribute('transform', `translate(0, ${groundY})`);
    } else {
        document.getElementById('ground-layer').style.display = 'none';
    }

    // --- HELICOPTER SPECIFIC DYNAMICS ---

    // Shift helicopter position horizontally on screen slightly based on velocity
    aircraftXOffset += (horizontalVelocity * 0.05);
    // Clamp horizontal screen offset to stay in view
    if (aircraftXOffset > 100) aircraftXOffset = 100;
    if (aircraftXOffset < -100) aircraftXOffset = -100;

    // Helicopter Pitch visually links to horizontal speed 
    // Nose tips DOWN (positive rotation) to go forward, UP (negative rotation) to go backward
    let visualPitch = horizontalVelocity * 0.5;
    visualPitch = Math.max(-25, Math.min(25, visualPitch)); 

    if (altitude <= 0.1 && verticalVelocity <= 0 && Math.abs(horizontalVelocity) < 1) visualPitch = 0; // Flat on ground

    document.getElementById('helicopter').setAttribute('transform', `rotate(${visualPitch})`);

    // Apply altitude and horizontal translation visually to the whole group
    document.getElementById('aircraft-group').setAttribute('transform', `translate(${385 + aircraftXOffset}, ${370 - (altitude * 0.5)})`);

    // Animate Rotor Spinning (Main and Tail)
    const spinScale = Math.cos(timestamp * 0.04); // Fast cosine wave for 3D spin effect
    document.getElementById('main-rotor-spin').setAttribute('transform', `translate(0, -45) scale(${spinScale}, 1)`);
    document.getElementById('tail-rotor-spin').setAttribute('transform', `translate(-150, -20) scale(1, ${spinScale})`);

    // Update UI Text
    document.getElementById('flight-status-alt').textContent = `ALTITUDE: ${Math.round(altitude * 10)} ft`;

    let speedStr = Math.round(Math.abs(horizontalVelocity * 10)) + ' kts';
    if (horizontalVelocity < -2) speedStr += ' (REV)';
    document.getElementById('flight-status-spd').textContent = `AIRSPEED: ${speedStr}`;

    const stateEl = document.getElementById('flight-state');
    if (altitude <= 0.1 && netY <= 0) {
        stateEl.textContent = "GROUNDED";
        stateEl.setAttribute('fill', '#94a3b8');
    } else if (verticalVelocity > 0.5) {
        stateEl.textContent = "CLIMBING";
        stateEl.setAttribute('fill', '#10b981');
    } else if (verticalVelocity < -0.5) {
        stateEl.textContent = "DESCENDING";
        stateEl.setAttribute('fill', '#ef4444');
    } else if (horizontalVelocity > 2) {
        stateEl.textContent = "FORWARD FLIGHT";
        stateEl.setAttribute('fill', '#3b82f6');
    } else if (horizontalVelocity < -2) {
        stateEl.textContent = "FLYING BACKWARD";
        stateEl.setAttribute('fill', '#f97316');
    } else {
        stateEl.textContent = "HOVERING";
        stateEl.setAttribute('fill', '#8b5cf6');
    }

    requestAnimationFrame(animationLoop);
}
